class Solution:
    def subarrayMajority(self, nums, queries):
        res = []
        for l, r, th in queries:
            freq = {}
            for i in range(l, r + 1):
                freq[nums[i]] = freq.get(nums[i], 0) + 1
            best = -1
            best_f = 0
            for v in sorted(freq):
                f = freq[v]
                if f >= th and f > best_f:
                    best_f = f
                    best = v
            res.append(best)
        return res

