class Solution:
    def subarrayMajority(self, nums, queries):
        from collections import Counter
        res = []
        for l, r, th in queries:
            c = Counter(nums[l:r + 1])
            best = -1
            best_f = 0
            for v in sorted(c):
                f = c[v]
                if f >= th and f > best_f:
                    best_f = f
                    best = v
            res.append(best)
        return res

