var subarrayMajority = function(nums, queries) {
    const res = [];
    for (const [l, r, th] of queries) {
        const c = new Map();
        for (let i = l; i <= r; i++) c.set(nums[i], (c.get(nums[i]) || 0) + 1);
        const keys = [...c.keys()].sort((a, b) => a - b);
        let best = -1, bestF = 0;
        for (const v of keys) {
            const f = c.get(v);
            if (f >= th && f > bestF) {
                bestF = f;
                best = v;
            }
        }
        res.push(best);
    }
    return res;
};
